const input = $input.first().json;
const action = input.action || 'list_bases';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const credRes = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.airtable&cred_key=eq.airtable_pat&select=cred_value',
  headers: pgHeaders
});
if (!credRes || !credRes[0] || !credRes[0].cred_value) {
  return [{ json: { error: 'Airtable PAT not configured. Use add_credential to set airtable_pat (create one at https://airtable.com/create/tokens with scopes: data.records:read, data.records:write, schema.bases:read).' } }];
}
const pat = credRes[0].cred_value;
const atHeaders = { 'Authorization': 'Bearer ' + pat, 'Content-Type': 'application/json' };
const API = 'https://api.airtable.com/v0';

function fmtFields(fields) {
  const out = [];
  for (const [k, v] of Object.entries(fields || {})) {
    let val;
    if (Array.isArray(v)) val = v.length > 3 ? v.slice(0, 3).join(', ') + ' +' + (v.length - 3) : v.join(', ');
    else if (typeof v === 'object' && v !== null) val = JSON.stringify(v);
    else val = String(v);
    if (val.length > 100) val = val.substring(0, 100) + '...';
    out.push(k + ': ' + val);
  }
  return out.join(' | ');
}

function parseFields(raw) {
  if (!raw) return {};
  if (typeof raw === 'object') return raw;
  try { return JSON.parse(raw); } catch (e) { throw new Error('Invalid fields JSON: ' + e.message + '. Must be a JSON object like {"Name":"Test","Status":"Done"}.'); }
}

async function req(method, path, body) {
  try {
    const opts = { method: method, url: API + path, headers: atHeaders };
    if (body) opts.body = JSON.stringify(body);
    return await helpers.httpRequest(opts);
  } catch (e) {
    const msg = e.message || String(e);
    if (msg.includes('401')) throw new Error('Unauthorized. Check your Airtable PAT.');
    if (msg.includes('403')) throw new Error('Forbidden. Your PAT does not have access to this base/table or lacks required scopes.');
    if (msg.includes('404')) throw new Error('Not found. Check base ID / table name / record ID.');
    if (msg.includes('422')) throw new Error('Unprocessable entity (422). Check that all field names and values match your table schema.');
    if (msg.includes('429')) throw new Error('Rate limited. Free plan: 5 req/sec per base, 1000 req/month total.');
    throw new Error(msg);
  }
}

// === list_bases ===
if (action === 'list_bases') {
  try {
    const r = await req('GET', '/meta/bases');
    const bases = r.bases || [];
    if (bases.length === 0) return [{ json: { result: 'No bases accessible with this PAT.' } }];
    let out = bases.length + ' base(s) accessible:\n\n';
    for (const b of bases) out += '- ' + b.name + ' (id: ' + b.id + ', permission: ' + b.permissionLevel + ')\n';
    return [{ json: { result: out } }];
  } catch (e) { return [{ json: { error: 'list_bases failed: ' + e.message } }]; }
}

// === list_tables ===
if (action === 'list_tables') {
  const baseId = input.base_id;
  if (!baseId) return [{ json: { error: 'Parameter "base_id" is required (e.g. appXXXXXXXX). Use list_bases to find it.' } }];
  try {
    const r = await req('GET', '/meta/bases/' + encodeURIComponent(baseId) + '/tables');
    const tables = r.tables || [];
    if (tables.length === 0) return [{ json: { result: 'No tables in base ' + baseId } }];
    let out = tables.length + ' table(s) in ' + baseId + ':\n\n';
    for (const t of tables) {
      out += '- ' + t.name + ' (id: ' + t.id + ')\n';
      if (t.fields) {
        const fields = t.fields.map(f => f.name + ' [' + f.type + ']');
        out += '  Fields: ' + fields.slice(0, 20).join(', ');
        if (fields.length > 20) out += ' +' + (fields.length - 20) + ' more';
        out += '\n';
      }
      if (t.views && t.views.length) {
        out += '  Views: ' + t.views.slice(0, 10).map(v => v.name).join(', ') + '\n';
      }
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (e) { return [{ json: { error: 'list_tables failed: ' + e.message } }]; }
}

// === list_records ===
if (action === 'list_records') {
  const baseId = input.base_id;
  const table = input.table;
  if (!baseId || !table) return [{ json: { error: 'Parameters "base_id" and "table" are required (table name or id).' } }];
  const params = [];
  const max = parseInt(input.max_records) || 10;
  params.push('maxRecords=' + max);
  if (input.view) params.push('view=' + encodeURIComponent(String(input.view)));
  if (input.filter_by_formula) params.push('filterByFormula=' + encodeURIComponent(String(input.filter_by_formula)));
  if (input.sort_field) {
    params.push('sort[0][field]=' + encodeURIComponent(String(input.sort_field)));
    params.push('sort[0][direction]=' + (input.sort_desc === 'true' || input.sort_desc === true ? 'desc' : 'asc'));
  }
  try {
    const r = await req('GET', '/' + encodeURIComponent(baseId) + '/' + encodeURIComponent(table) + '?' + params.join('&'));
    const records = r.records || [];
    if (records.length === 0) return [{ json: { result: 'No records found.' } }];
    let out = records.length + ' record(s) from "' + table + '":\n\n';
    for (const rec of records) {
      out += '- ' + rec.id + ': ' + fmtFields(rec.fields) + '\n';
    }
    if (r.offset) out += '\n(more records available, use higher max_records)';
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (e) { return [{ json: { error: 'list_records failed: ' + e.message } }]; }
}

// === get_record ===
if (action === 'get_record') {
  const baseId = input.base_id;
  const table = input.table;
  const recId = input.record_id;
  if (!baseId || !table || !recId) return [{ json: { error: 'Parameters "base_id", "table", and "record_id" are required.' } }];
  try {
    const r = await req('GET', '/' + encodeURIComponent(baseId) + '/' + encodeURIComponent(table) + '/' + encodeURIComponent(recId));
    let out = 'Record ' + r.id + ' (created ' + r.createdTime + '):\n';
    for (const [k, v] of Object.entries(r.fields || {})) {
      let val;
      if (Array.isArray(v)) val = v.join(', ');
      else if (typeof v === 'object' && v !== null) val = JSON.stringify(v);
      else val = String(v);
      out += '  ' + k + ': ' + val + '\n';
    }
    return [{ json: { result: out } }];
  } catch (e) { return [{ json: { error: 'get_record failed: ' + e.message } }]; }
}

// === create_record ===
if (action === 'create_record') {
  const baseId = input.base_id;
  const table = input.table;
  if (!baseId || !table) return [{ json: { error: 'Parameters "base_id" and "table" are required.' } }];
  let fields;
  try { fields = parseFields(input.fields); } catch (e) { return [{ json: { error: e.message } }]; }
  if (!fields || Object.keys(fields).length === 0) return [{ json: { error: 'Parameter "fields" is required (JSON object with field names and values, e.g. {"Name":"Test","Status":"Done"}).' } }];
  try {
    const r = await req('POST', '/' + encodeURIComponent(baseId) + '/' + encodeURIComponent(table), { fields: fields });
    return [{ json: { result: 'Created record ' + r.id + '\n' + fmtFields(r.fields) } }];
  } catch (e) { return [{ json: { error: 'create_record failed: ' + e.message } }]; }
}

// === update_record ===
if (action === 'update_record') {
  const baseId = input.base_id;
  const table = input.table;
  const recId = input.record_id;
  if (!baseId || !table || !recId) return [{ json: { error: 'Parameters "base_id", "table", and "record_id" are required.' } }];
  let fields;
  try { fields = parseFields(input.fields); } catch (e) { return [{ json: { error: e.message } }]; }
  if (!fields || Object.keys(fields).length === 0) return [{ json: { error: 'Parameter "fields" is required (JSON object with fields to update).' } }];
  try {
    const r = await req('PATCH', '/' + encodeURIComponent(baseId) + '/' + encodeURIComponent(table) + '/' + encodeURIComponent(recId), { fields: fields });
    return [{ json: { result: 'Updated record ' + r.id + '\n' + fmtFields(r.fields) } }];
  } catch (e) { return [{ json: { error: 'update_record failed: ' + e.message } }]; }
}

// === delete_record ===
if (action === 'delete_record') {
  const baseId = input.base_id;
  const table = input.table;
  const recId = input.record_id;
  if (!baseId || !table || !recId) return [{ json: { error: 'Parameters "base_id", "table", and "record_id" are required.' } }];
  try {
    const r = await req('DELETE', '/' + encodeURIComponent(baseId) + '/' + encodeURIComponent(table) + '/' + encodeURIComponent(recId));
    return [{ json: { result: 'Deleted record ' + (r.id || recId) } }];
  } catch (e) { return [{ json: { error: 'delete_record failed: ' + e.message } }]; }
}

return [{ json: { error: 'Unknown action: ' + action + '. Available: list_bases, list_tables, list_records, get_record, create_record, update_record, delete_record.' } }];
